class Solution:
    def cycleUtil(self, g, node, visited):
        visited[node] = True
        for neighbor in g[node]:
            if neighbor == node or (visited[neighbor] and not visited[node]):
                return True
            if not self.cycleUtil(g, neighbor, visited):
                return False
        return False

    def isCycle(self, g):
        visited = [False] * len(g)
        res = False
        for node in range(len(g)):
            if not visited[node]:
                res |= self.cycleUtil(g, node, visited)
        return res

