class Solution {
public:
bool isCycle(vector<vector<int>>& g) {
	vector<bool> visited;
	for (int node = 0; node != g.size(); ++node) {
		visited.push_back(false);
	}
	bool res = false;
	for (int node = 0; node != g.size(); ++node) {
		if (!visited[node]) {
			res |= cycleUtil(g, node, visited);
		}
	}
	return res;
}
bool cycleUtil(vector<vector<int>>& g, int node, vector<bool>& visited) {
	visited[node] = true;
	for (int neighbor : g[node]) {
		if (neighbor == node || (visited[neighbor] && !visited[node])) return true;
		if (!cycleUtil(g, neighbor, visited)) return false;
	}
	return false;
}
};
sol = Solution(); testcases = {{1,2},{2,3},{3,4},{4,1}}; cout << (sol.isCycle(testcases) ? 'true' : 'false') << endl;
